import React, { useState, useEffect } from 'react';
import { Button, Box, FormControl, InputLabel, Select, MenuItem } from '@mui/material';
import axios from 'axios';
import CreatePricingForm from './CreatePricingForm'; // Ensure this path is correct

const PricingPage = () => {
  const [selectedCustomer, setSelectedCustomer] = useState('');
  const [customers, setCustomers] = useState([]);
  const [isFormOpen, setFormOpen] = useState(false);

  useEffect(() => {
    axios.get('http://localhost:5000/api/customers')
      .then(response => {
        setCustomers(response.data);
      })
      .catch(error => {
        console.error('Error fetching customers:', error);
      });
  }, []);

  const handleCustomerChange = (event) => {
    setSelectedCustomer(event.target.value);
    setFormOpen(true);
  };

  return (
    <div>
      <h1>Pricing Management</h1>
      <p>Welcome to the Pricing Management page. Here you can manage all pricing related tasks.</p>
      <FormControl fullWidth margin="normal">
        <InputLabel id="customer-select-label">Customer</InputLabel>
        <Select
          labelId="customer-select-label"
          id="customer-select"
          value={selectedCustomer}
          label="Customer"
          onChange={handleCustomerChange}
        >
          <MenuItem value="">
            <em>Select a customer</em>
          </MenuItem>
          {customers.map((customer) => (
            <MenuItem key={customer.id} value={customer.id}>
              {customer.id} {customer.name}
            </MenuItem>
          ))}
        </Select>
      </FormControl>
      {isFormOpen && <CreatePricingForm customerId={selectedCustomer} handleClose={() => setFormOpen(false)} />}
    </div>
  );
};

export default PricingPage;
